class Solution {
    public List<Integer> splitIntoFibonacci(String num) {
        List<Integer> result = new ArrayList<>();
        if (num.length() < 3) {
            return result;
        }
        for (int i = 1; i <= num.length() / 3; i++) {
            long first = Long.parseLong(num.substring(0, i));
            if (first > Integer.MAX_VALUE || first < 0) {
                continue;
            }
            for (int j = i + 1; j <= num.length() / 2; j++) {
                long second = Long.parseLong(num.substring(i, j));
                if (second > Integer.MAX_VALUE || second < 0) {
                    continue;
                }
                long third = Long.parseLong(num.substring(j));
                if (third > Integer.MAX_VALUE || third < 0) {
                    continue;
                }
                if (first + second == third) {
                    result.add((int) first);
                    result.add((int) second);
                    result.add((int) third);
                    return result;
                }
            }
        }
        return result;
    }
}
